import{_ as e,c as i,o as t,ae as o}from"./chunks/framework.-A2PGuvX.js";const u=JSON.parse('{"title":"Pagination","description":"","frontmatter":{},"headers":[],"relativePath":"services/pagination/index.md","filePath":"services/pagination/index.md"}'),r={name:"services/pagination/index.md"};function n(s,a,l,d,c,g){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h1><p>Pagination is built around three parts:</p><ol><li><strong>Data drivers</strong> fetch pages and return a <code>PaginationDataDto</code>.</li><li><strong>View drivers</strong> store pagination state (page, size, total) and expose page data.</li><li><strong>Paginators</strong> orchestrate loading and state updates.</li></ol><h2 id="drivers" tabindex="-1">Drivers <a class="header-anchor" href="#drivers" aria-label="Permalink to &quot;Drivers&quot;">​</a></h2><p>Pagination uses two kinds of drivers:</p><ul><li><strong>Data drivers</strong> fetch pages and return a <code>PaginationDataDto</code>.</li><li><strong>View drivers</strong> store pagination state (page, size, total) and expose page data.</li></ul><p>You can implement your own drivers by following these contracts:</p><ul><li><code>PaginationDataDriverContract</code> or <code>StatePaginationDataDriverContract</code> for data drivers</li><li><code>ViewDriverFactoryContract</code> or <code>BaseViewDriverFactoryContract</code> for view drivers</li></ul><p>If you are using Vue, the library provides <code>VuePaginationDriverFactory</code> and <code>VueBaseViewDriverFactory</code>.</p><h3 id="built-in-data-drivers" tabindex="-1">Built-in Data Drivers <a class="header-anchor" href="#built-in-data-drivers" aria-label="Permalink to &quot;Built-in Data Drivers&quot;">​</a></h3><ul><li><code>ArrayDriver</code>: paginate an in-memory array.</li><li><code>RequestDriver</code>: paginate using a request. See the Laravel pagination integration for usage details.</li></ul><h2 id="paginators" tabindex="-1">Paginators <a class="header-anchor" href="#paginators" aria-label="Permalink to &quot;Paginators&quot;">​</a></h2><ul><li><a href="./page-aware.html">Page-Aware Pagination</a></li><li><a href="./infinite-scroller.html">Infinite Scroll</a></li><li><a href="./state-pagination.html">State/Cursor Pagination</a></li></ul><h2 id="load-options" tabindex="-1">Load Options <a class="header-anchor" href="#load-options" aria-label="Permalink to &quot;Load Options&quot;">​</a></h2><p><code>load()</code> accepts <code>PaginatorLoadDataOptions</code>:</p><ul><li><code>flush</code>: clears existing data before applying the next page</li><li><code>replace</code>: replaces existing data instead of appending (useful for infinite scroll)</li></ul><p><code>updateRows</code> is available on all paginators. See <a href="./updating-rows.html">Updating Rows</a>.</p><h2 id="using-laravel-pagination" tabindex="-1">Using Laravel Pagination <a class="header-anchor" href="#using-laravel-pagination" aria-label="Permalink to &quot;Using Laravel Pagination&quot;">​</a></h2><p>If you use Laravel pagination responses, see the Laravel pagination docs for the <code>PaginationJsonBaseRequest</code> and <code>RequestDriver</code> integration.</p>',19)])])}const h=e(r,[["render",n]]);export{u as __pageData,h as default};
